+        let mut config = FsTwoTierConfig::default();
+        match self {
+            Self::Single | Self::Progressive => {}
+            Self::FastOnly => {
+                config.fast_only = true;
+            }
+            Self::QualityOnly => {
+                config.quality_weight = 1.0;
+            }
+        }
