+impl LazyFrankenDb {
+    /// Create a lazy handle pointing at `path`.  No I/O is performed.
+    pub fn new(path: PathBuf) -> Self {
+        Self {
+            path,
+            conn: parking_lot::Mutex::new(None),
+        }
+    }
+
+    /// Resolve path from optional CLI overrides.
