+    /// Uses `data_dir / agent_search.db` as fallback.
+    pub fn from_overrides(data_dir: &Option<PathBuf>, db_override: Option<PathBuf>) -> Self {
+        let data_dir = data_dir.clone().unwrap_or_else(crate::default_data_dir);
